   139ã    --space-sm: 0.5rem;    /* 8px */
   140ã    --space-md: 0.75rem;   /* 12px */
   141ã    --space-base: 1rem;    /* 16px */
   142ã    --space-lg: 1.5rem;    /* 24px */
