   149ã     * oklch color space for perceptual uniformity.
   150ã     * Most UI is grayscale; color is for emphasis and interaction.
   151ã     *
   152ã     * oklch(Lightness Chroma Hue)
   153ã     * - Lightness: 0 (black) to 1 (white)
   154ã     * - Chroma: 0 (gray) to ~0.4 (most saturated)
   155ã     * - Hue: 0-360 degrees
   156ã     */
   157ã
   158ã    /* Neutral grays -- zero chroma for true neutrals */
   159ã    --color-gray-50:  oklch(0.985 0 0);
   160ã    --color-gray-100: oklch(0.96 0 0);
   161ã    --color-gray-200: oklch(0.9 0 0);
