   205ã    --font-size-sm:   clamp(0.8125rem, 0.775rem + 0.25vw, 0.875rem); /* ~13-14px */
   206ã    --font-size-base: clamp(0.875rem, 0.825rem + 0.3vw, 1rem);       /* ~14-16px */
   207ã    --font-size-md:   clamp(1rem, 0.925rem + 0.4vw, 1.125rem);       /* ~16-18px */
