   251ã    --focus-ring-width:  2px;
   252ã  }
   253ã}
   254ã
   255ã/* ==========================================================================
   256ã   BASE LAYER
   257ã   Element-level styles applied directly to HTML elements.
   258ã   No classes -- this establishes the typographic and interactive baseline.
   259ã   ========================================================================== */
   260ã
   261ã@layer base {
